/**
 * Lead-gen automation blueprints — the proven, hard-coded cadences every client
 * gets on onboarding. Timing lives here (battle-tested); the COPY for each
 * message step is generated by Claude at onboard time (tailored to the client),
 * with the `fallback` copy used if generation fails so a workflow is never empty.
 *
 * Message steps carry: { type, brief, fallback }.
 *   send_sms   fallback: string
 *   send_email fallback: { subject, html }
 * Structural steps: { type: 'wait', minutes|hours|days }, { type: 'add_tag'|'remove_tag', tag }.
 *
 * All copy may use merge tags: {{firstName}} {{lastName}} {{fullName}} {{business}}
 * {{repName}} {{bookingLink}} {{offer}} {{email}} {{phone}}.
 */

const emailWrap = (inner, cta) => `<div style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;font-size:15px;line-height:1.6;color:#222;max-width:560px">`
  + inner
  + (cta ? `<p style="margin:24px 0"><a href="{{bookingLink}}" style="background:#7c3aed;color:#fff;text-decoration:none;padding:12px 22px;border-radius:10px;display:inline-block;font-weight:600">${cta}</a></p>` : '')
  + `<p style="margin-top:24px;color:#555">— {{repName}}, {{business}}</p></div>`

