/** Steps that carry copy (need AI generation), in order, with their channel + brief. */
export function messageSteps(bp) {
  return bp.steps
    .map((s, i) => ({ ...s, index: i }))
    .filter(s => s.type === 'send_sms' || s.type === 'send_email')
}

/** Build engine-format steps for a blueprint, applying generated copy where present. */
export function assembleSteps(bp, copyByIndex = {}) {
  return bp.steps.map((s, i) => {
    if (s.type === 'send_sms') {
      const c = copyByIndex[i]
      return { type: 'send_sms', body: (c && c.text) || s.fallback }
    }
    if (s.type === 'send_email') {
      const c = copyByIndex[i]
      return {
        type: 'send_email',
        subject: (c && c.subject) || s.fallback?.subject || '',
        body:    (c && c.html)    || s.fallback?.html || '',
      }
    }
    if (s.type === 'wait') {
      return { ...s } // already { type:'wait', minutes|hours|days }
    }
    if (s.type === 'add_tag' || s.type === 'remove_tag') {
      return { type: s.type, tag: s.tag }
    }
    return { type: s.type }
  })
}
